SELECT setval(pg_get_serial_sequence('meal', 'id'), COALESCE((SELECT MAX(id) FROM meal), 1), true);
SELECT setval(pg_get_serial_sequence('reservation', 'id'), COALESCE((SELECT MAX(id) FROM reservation), 1), true);
SELECT setval(pg_get_serial_sequence('review', 'id'), COALESCE((SELECT MAX(id) FROM review), 1), true);

COMMIT;
